// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('text box name or email', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('text box name or email', async function() {
    await driver.get("http://localhost:4200/admin-user/add-user");
    await driver.manage().window().setRect({ width: 1920, height: 1040 });
    await driver.findElement(By.id("email")).click();
    await driver.findElement(By.id("email")).sendKeys("11111111111111111111");
    vars["buttonSearchDisable"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[0].disabled");
    assert(vars["buttonSearchDisable"].toString() == "false");
    await driver.findElement(By.id("email")).sendKeys("222222222222222222222222222222");
    vars["buttonSearchDisable"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[0].disabled");
    assert(vars["buttonSearchDisable"].toString() == "false");
    await driver.findElement(By.id("email")).sendKeys("333333333333333333333333333333");
    vars["buttonSearchDisable"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[0].disabled");
    assert(vars["buttonSearchDisable"].toString() == "false");
    await driver.findElement(By.id("email")).sendKeys("3333333333333333333333333333333");
    vars["buttonSearchDisable"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[0].disabled");
    assert(vars["buttonSearchDisable"].toString() == "true");
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "30文字以内で入力してください。");
    await driver.findElement(By.id("email")).sendKeys("4444444444444444444444444444444444444444");
    vars["buttonSearchDisable"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[0].disabled");
    assert(vars["buttonSearchDisable"].toString() == "true");
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "30文字以内で入力してください。");
  });
});
